INSERT INTO `recetas` VALUES (1,1,'Bombon Diabetic-Care',1,'1.	Fundición: Derretir el chocolate a baño maría hasta los 50°C. No exceder, o el sustituto de azúcar se granulado.\r\n2.	Atemperado: Verter 2/3 en mármol y trabajar con espátula hasta bajar a 27°C. Regresar al bol con el resto para estabilizar en 31°C.\r\n3.	Montaje: Extender en molde, vibrar 30 segundos para sacar aire. Espolvorear la almendra y la sal.\r\n4.	Cristalización: 15 min en refrigeración controlado a 14°C.',1),(2,2,'Trufa Imperial Oro',1,'1.	Emulsión: Hervir la crema y verter en tres partes sobre el chocolate picado, mezclando desde el centro hacia afuera en círculos.\r\n2.	Reposo: Dejar la ganache 12 horas a temperatura ambiente para que tome cuerpo.\r\n3.	Acabado: Formar el lingote. Al momento de empacar, aplicar el oro con pinza de bambú (la estática ayuda a que se pegue).',1),(3,3,'Barra Fit Protein - 70% Cacao',1,'1.	Integración: Fundir chocolate y manteca a 50°C. Agregar la proteína tamizada (pasada por colador).\r\n2.	Homogeneización: Batir con batidor de globo intensamente hasta que no haya rastro de polvo.\r\n3.	Moldeo: Bajar temperatura a 31°C. Esta mezcla espesa rápido, moldear de inmediato.',1),(4,4,'Pistacho Delight - Blanco',1,'1.	Base: Fundir chocolate blanco a 45°C.\r\n2.	Mezcla: Incorporar la pasta de pistacho fría y mezclar hasta obtener un verde pálido uniforme.\r\n3.	Choque Térmico: Bajar a 28°C para asegurar que la manteca de cacao del blanco cristalice correctamente.',1),(5,5,'Avellana Crunch Vegano',1,'1.	Tostado: Hornear la avellana 5 min a 160°C para despertar aceites antes de mezclar.\r\n2.	Cristalización: El chocolate de coco es más blando; temperar a 29°C máximo. Mezclar el \"crunch\" y verter.',1),(6,6,'Vainilla SKY',1,'1.	Extracción: Abrir la vaina, raspar las semillas negras.\r\n2.	Infusión: Mezclar las semillas con el chocolate líquido y dejar reposar 10 min a 40°C para que el aroma se libere antes de templar.',1),(7,7,'Gema Esmeralda',1,'1.	Camisa: Pintar el molde con chocolate amargo temperado. Voltear el molde para eliminar exceso.\r\n2.	Relleno: Una vez seco, rellenar (dejar 2mm de margen).\r\n3.	Cierre: Cubrir con chocolate amargo para sellar la \"Gema\".',1),(8,8,'Mar de Java',1,'1.	Temperado: Chocolate Java requiere precisión a 30°C.\r\n2.	Decorado: La sal ahumada solo va en la base de la barra (la parte que toca la lengua primero al comer) para potenciar el perfil de sabor.',1),(9,9,'Energy Chia',1,'1.	Mezcla: Añadir la chía seca al chocolate ya temperado.\r\n2.	Vibrado: Vibrar la bandeja con fuerza extra para que la chía se asiente uniformemente y no flote.',1),(10,10,'Double Muscle',1,'1.	Compresión: Mezclar proteína y chocolate. Al ser mucha carga seca, la mezcla quedará pastosa.\r\n2.	Prensado: Usar moldes de silicona y presionar con espátula para evitar burbujas internas de aire.',1),(11,11,'Receta Amazonas',1,'1.	Fundición: Derretir el chocolate a 55°C. Al ser casi puro cacao, la viscosidad es alta.\r\n2.	Atemperado: Trabajar intensamente en mármol para bajar a 28°C. Subir a 31.5°C para trabajar. Si baja de 31°C, se endurecerá muy rápido.\r\n3.	Moldeo: Verter en moldes precalentados (a unos 25°C) para evitar un choque térmico que opaque el brillo.\r\n4.	Desmolde: Dejar cristalizar a 16-18°C. El sonido al romperlo debe ser un \"crack\" seco y fuerte.',1);
/*!40000 ALTER TABLE `recetas` ENABLE KEYS */;
UNLOCK TABLES;
